<?php
namespace Tests\Feature\Admin\Content;
use App\Domain\Loot\LootGenerator;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class AdminLootManagementTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();config(['game_admin.emails'=>['loot-admin@example.test']]);$this->admin=User::factory()->create(['email'=>'loot-admin@example.test']);$this->actingAs($this->admin);}private function monster($code='loot_admin_monster'){return Monster::create(['code'=>$code,'name'=>'Loot Admin Monster','description'=>null,'level'=>1,'max_health'=>10,'attack'=>1,'defense'=>1,'accuracy_rate'=>80,'evasion_rate'=>0,'critical_chance'=>0,'experience_reward'=>1,'gold_min'=>0,'gold_max'=>0,'status'=>'active']);}private function item($code,$stackable=true){return Item::create(['code'=>$code,'name'=>$code,'description'=>null,'item_type'=>$stackable?'material':'equipment','equipment_type'=>$stackable?null:'weapon','rarity'=>'common','is_stackable'=>$stackable,'max_stack'=>$stackable?99:1,'status'=>'active']);}private function payload(Item $item,$overrides=[]){return array_merge(['item_id'=>$item->id,'drop_chance_basis_points'=>7000,'minimum_quantity'=>1,'maximum_quantity'=>2,'status'=>'active','sort_order'=>3],$overrides);}public function test_monster_page_has_help_preloaded_editing_and_percentage(){ $monster=$this->monster();$item=$this->item('help_item');$entry=MonsterLootEntry::create(array_merge($this->payload($item),['monster_id'=>$monster->id]));$this->get(route('admin.content.monsters.show',$monster))->assertOk()->assertSee('Objeto que el monstruo puede entregar al ser derrotado.')->assertSee('10000 equivale a 100 %')->assertSee('70 %')->assertSee('Guardar cambios')->assertSee('value="7000"',false)->assertSee('Editar')->assertSee('Desactivar');}
public function test_general_update_changes_item_values_and_state_without_duplicate(){ $monster=$this->monster();$old=$this->item('old_drop');$new=$this->item('new_drop');$entry=MonsterLootEntry::create(array_merge($this->payload($old),['monster_id'=>$monster->id]));$this->put(route('admin.content.monsters.loot.update',[$monster,$entry]),$this->payload($new,['drop_chance_basis_points'=>5000,'minimum_quantity'=>4,'maximum_quantity'=>7,'status'=>'inactive','sort_order'=>9]))->assertRedirect(route('admin.content.monsters.show',$monster))->assertSessionHas('status','Loot actualizado correctamente.');$this->assertSame(1,MonsterLootEntry::count());$entry=$entry->fresh();$this->assertSame($new->id,$entry->item_id);$this->assertSame(5000,$entry->drop_chance_basis_points);$this->assertSame(4,$entry->minimum_quantity);$this->assertSame(7,$entry->maximum_quantity);$this->assertSame(9,$entry->sort_order);$this->assertSame('inactive',$entry->status);$duplicate=MonsterLootEntry::create(array_merge($this->payload($old),['monster_id'=>$monster->id]));$this->put(route('admin.content.monsters.loot.update',[$monster,$entry]),$this->payload($old))->assertSessionHasErrors('item_id');$this->assertSame($new->id,$entry->fresh()->item_id);$other=$this->monster('other_monster');$this->put(route('admin.content.monsters.loot.update',[$other,$duplicate]),$this->payload($old))->assertNotFound();}
public function test_explicit_status_actions_preserve_fields_and_reactivation_restores_generator(){ $monster=$this->monster();$item=$this->item('status_drop');$entry=MonsterLootEntry::create(array_merge($this->payload($item,['drop_chance_basis_points'=>10000,'minimum_quantity'=>2,'maximum_quantity'=>2,'sort_order'=>8]),['monster_id'=>$monster->id]));$before=$entry->only(['item_id','drop_chance_basis_points','minimum_quantity','maximum_quantity','sort_order']);$this->patch(route('admin.content.monsters.loot.deactivate',[$monster,$entry]))->assertSessionHas('status','Loot desactivado correctamente.');$entry=$entry->fresh();$this->assertSame('inactive',$entry->status);$this->assertSame($before,$entry->only(array_keys($before)));$this->assertCount(0,app(LootGenerator::class)->generateFor($monster)->drops());$this->patch(route('admin.content.monsters.loot.activate',[$monster,$entry]))->assertSessionHas('status','Loot activado correctamente.');$entry=$entry->fresh();$this->assertSame('active',$entry->status);$this->assertSame($before,$entry->only(array_keys($before)));$this->assertCount(1,app(LootGenerator::class)->generateFor($monster)->drops());}
public function test_non_stackable_quantities_are_rejected_by_request(){ $monster=$this->monster();$unique=$this->item('unique_drop',false);$this->post(route('admin.content.monsters.loot.store',$monster),$this->payload($unique,['minimum_quantity'=>1,'maximum_quantity'=>2]))->assertSessionHasErrors('maximum_quantity');$this->assertDatabaseMissing('monster_loot_entries',['monster_id'=>$monster->id,'item_id'=>$unique->id]);}}
